	}
	if cfg1 == nil {
		t.Fatalf("expected non-nil config")
	}

	cfg2, err := LoadEconomicsConfig()
	if err != nil {
		t.Fatalf("unexpected error on second load: %v", err)
	}

	if economicConfig == nil {
